function BottomTabBar({ activeTab, onTabPress }) {
  const tabs = [
    { key: 'home', label: '🏠', labelText: 'Accueil' },
    { key: 'search', label: '🔍', labelText: 'Recherche' },
    { key: 'profile', label: '👤', labelText: 'Profil' },
  ];

  return (
    <View style={styles.container}>
      {tabs.map((tab) => (
        <TouchableOpacity
          key={tab.key}
          style={styles.tab}
          onPress={() => onTabPress(tab.key)}
        >
          <Text style={[styles.icon, activeTab === tab.key && styles.activeIcon]}>
            {tab.label}
          </Text>
          <Text style={[styles.label, activeTab === tab.key && styles.activeLabel]}>
            {tab.labelText}
          </Text>
        </TouchableOpacity>
      ))}
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    flexDirection: 'row',
    backgroundColor: 'white',
    paddingVertical: 10,
    paddingBottom: 20,
    borderTopWidth: 1,
    borderTopColor: '#eee',
    position: 'absolute',
    bottom: 0,
    left: 0,
    right: 0,
  },
  tab: {
    flex: 1,
    alignItems: 'center',
    justifyContent: 'center',
  },
  icon: {
    fontSize: 24,
    color: '#999',
  },
  activeIcon: {
    color: '#0066cc',
  },
  label: {
    fontSize: 10,
    color: '#999',
    marginTop: 4,
  },
  activeLabel: {
    color: '#0066cc',
  },
});
